#include<bits/stdc++.h>
#define int long long
using namespace std;
struct node {
	int v;
	int x;
} a[1000010];
int n;
int tree1[1000010];
int tree2[1000010];
int ans;
int summ;
const int nn = 50000;
bool cmp(node x,node y) {
	return x.v < y.v;
}
int lowbit(int x) {
	return x & -x;
}
void update1(int i,int x) {
	for( ; i <= nn ; i += lowbit( i ) ) {
		tree1[i] += x;
	}
}
int getsum1(int x) {
	int s = 0;
	for( ; x ; x -= lowbit( x ) ) {
		s += tree1[x];
	}
	return s;
}
void update2( int i , int x ) {
	for( ; i <= nn ; i += lowbit( i ) ) {
		tree2[i] += x;
	}
}
int getsum2(int x) {
	int s = 0;
	for( ; x ; x -= lowbit( x ) ) {
	    s += tree2[x];
	}
	return s;
}
signed main() {
	cin>>n;
	for( int i = 1 ; i <= n ; i++ ) {
		cin >> a[i].v >> a[i].x;
	}
	sort( a + 1 , a + n + 1 , cmp );
	for( int i = 1; i <= n ; i ++) {
		int num = getsum1( a[i].x );
		int sum = getsum2( a[i].x );
		ans += ( num * a[i].x - sum ) * a[i].v;
		ans += ( ( summ - sum ) - ( i - num - 1 ) * a[i].x ) * a[i].v;
		update1( a[i].x , 1 );
		update2( a[i].x,a[i].x );
		summ += a[i].x;
	}
	cout << ans;
	return 0;
}
